// TypeScript implementation for Path Mapping Configs
interface PathMappingConfigsPayload {
  id: number;
  title: string;
  status: 'active' | 'pending';
}

function processPathMappingConfigs(item: PathMappingConfigsPayload): string {
  return `[${item.id}] ${item.title}: ${item.status}`;
}

console.log(processPathMappingConfigs({ id: 1, title: 'Path Mapping Configs', status: 'active' }));

